package com.enigma.familylinklite;

import android.Manifest;import android.app.*;import android.app.admin.DevicePolicyManager;import android.content.*;import android.graphics.*;import android.media.*;import android.net.wifi.WifiManager;import android.os.*;import android.provider.Settings;import android.text.format.Formatter;import android.view.*;import android.widget.*;import com.google.zxing.*;import com.google.zxing.common.BitMatrix;import org.json.*;import java.io.*;import java.net.*;import java.nio.charset.StandardCharsets;import java.security.*;import java.util.*;import javax.crypto.*;import javax.crypto.spec.*;

public class MainActivity extends Activity{
    static final int PORT=45454, DISCOVERY_PORT=45455; LinearLayout root; byte[] key; String childIp="", childId=""; TextView log,status,screenTime,topApps; BroadcastReceiver br; Thread discoveryThread; volatile boolean discoveryRunning=false; int parentVolume=50;
    public void onCreate(Bundle b){super.onCreate(b); getWindow().setSoftInputMode(WindowManager.LayoutParams.SOFT_INPUT_ADJUST_RESIZE); if(Build.VERSION.SDK_INT>=33)requestPermissions(new String[]{Manifest.permission.POST_NOTIFICATIONS},7); String mode=getSharedPreferences("p",0).getString("mode",""); if("parent".equals(mode)&&hasParentSaved())showParentConnected(); else if("child".equals(mode))showChild(); else showStart();}
    protected void onDestroy(){discoveryRunning=false;try{if(br!=null)unregisterReceiver(br);}catch(Exception ignored){}super.onDestroy();}
    TextView tv(String s,int sp){TextView v=new TextView(this);v.setText(s);v.setTextSize(sp);v.setPadding(18,12,18,12);return v;} Button btn(String s){Button b=new Button(this);b.setText(s);b.setAllCaps(false);return b;} EditText edit(String hint){EditText e=new EditText(this);e.setHint(hint);e.setSingleLine(false);e.setMinLines(2);e.setPadding(18,12,18,12);return e;}
    void base(){ScrollView sv=new ScrollView(this);root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setPadding(24,32,24,32);sv.addView(root);setContentView(sv);log=tv("",14);} 
    void header(String title,boolean plus){LinearLayout row=new LinearLayout(this);row.setOrientation(LinearLayout.HORIZONTAL);TextView t=tv(title,24);row.addView(t,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1)); if(plus){Button p=btn("+");p.setTextSize(24);p.setOnClickListener(v->showParentPairing());row.addView(p);} root.addView(row);} 
    void showStart(){base();header("FamilyLink Lite",false);root.addView(tv("Choose this device's function.",16));Button p=btn("Parent phone");Button c=btn("Child tablet");root.addView(p);root.addView(c);p.setOnClickListener(v->{getSharedPreferences("p",0).edit().putString("mode","parent").apply();showParentPairing();});c.setOnClickListener(v->{getSharedPreferences("p",0).edit().putString("mode","child").apply();showChild();});}
    boolean hasParentSaved(){String k=getSharedPreferences("p",0).getString("parentKey",null);return k!=null&&k.length()>10;} 
    void loadParent(){childIp=getSharedPreferences("p",0).getString("childIp","");childId=getSharedPreferences("p",0).getString("childId","");key=Base64.getDecoder().decode(getSharedPreferences("p",0).getString("parentKey",""));}

    void showParentPairing(){base();header("Add child device",false);EditText pairing=edit("Paste child pairing code: ip:45454:key:childId");root.addView(pairing);Button save=btn("Save connection");root.addView(save);save.setOnClickListener(v->{try{String code=pairing.getText().toString().trim();String[] p=code.split(":");childIp=p[0];key=Base64.getDecoder().decode(p[2]);childId=p.length>=4?p[3]:String.valueOf(checkCode(code));getSharedPreferences("p",0).edit().putString("mode","parent").putString("childIp",childIp).putString("childId",childId).putString("parentKey",Base64.getEncoder().encodeToString(key)).apply();toast("Saved. Check code: "+checkCode(code));showParentConnected();}catch(Exception e){toast("Invalid pairing code");}});}

    void showParentConnected(){base();header("FamilyLink Lite",true);try{loadParent();}catch(Exception e){showParentPairing();return;} LinearLayout strow=new LinearLayout(this);strow.setOrientation(LinearLayout.HORIZONTAL);status=tv("Disconnected",18);status.setBackgroundColor(Color.rgb(255,210,210));Button refresh=btn("↻");refresh.setOnClickListener(v->{out("Manual reconnect requested");cmd("usage","today");});strow.addView(status,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));strow.addView(refresh);root.addView(strow);
        screenTime=tv("Today's screen time: --:--",18);topApps=tv("Most active apps:\n1. --\n2. --\n3. --",16);root.addView(screenTime);root.addView(topApps);root.addView(tv("Commands",18));
        LinearLayout volRow=new LinearLayout(this);volRow.setOrientation(LinearLayout.HORIZONTAL);Button down=btn("Volume -");Button up=btn("Volume +");Button mute=btn("Mute");volRow.addView(down,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));volRow.addView(up,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));volRow.addView(mute,new LinearLayout.LayoutParams(0,ViewGroup.LayoutParams.WRAP_CONTENT,1));root.addView(volRow);TextView volLabel=tv("Requested volume: "+parentVolume+"%",16);root.addView(volLabel);down.setOnClickListener(v->{parentVolume=Math.max(0,parentVolume-10);volLabel.setText("Requested volume: "+parentVolume+"%");cmd("volume",String.valueOf(parentVolume));});up.setOnClickListener(v->{parentVolume=Math.min(100,parentVolume+10);volLabel.setText("Requested volume: "+parentVolume+"%");cmd("volume",String.valueOf(parentVolume));});mute.setOnClickListener(v->{parentVolume=0;volLabel.setText("Requested volume: 0%");cmd("volume","0");});
        EditText msg=edit("Message to child");root.addView(msg);Button send=btn("Send message");Button ping=btn("Ping / make sound");Button stop=btn("Stop ping");Button usage=btn("Refresh screen time");for(Button b:new Button[]{send,ping,stop,usage})root.addView(b);send.setOnClickListener(v->cmd("message",msg.getText().toString()));ping.setOnClickListener(v->cmd("ping","start"));stop.setOnClickListener(v->cmd("ping","stop"));usage.setOnClickListener(v->cmd("usage","today"));root.addView(log);startDiscoveryListener();cmd("usage","today");}

    void showChild(){key=getOrCreateKey();childId=getOrCreateChildId();base();header("Child tablet mode",false);String ip=getIp();String pair=ip+":"+PORT+":"+Base64.getEncoder().encodeToString(key)+":"+childId;root.addView(tv("Same Wi-Fi IP: "+ip,16));root.addView(tv("5-digit check code: "+checkCode(pair),22));root.addView(tv("Paste this pairing code into the parent app. The QR contains the same code.",16));TextView code=tv(pair,13);code.setTextIsSelectable(true);root.addView(code);ImageView qr=new ImageView(this);qr.setImageBitmap(qrBitmap(pair,600));root.addView(qr);Button start=btn("Start / restart child background server");Button stop=btn("Stop child background server");Button usage=btn("Open Usage Access settings");Button admin=btn("Enable device admin");root.addView(start);root.addView(stop);root.addView(usage);root.addView(admin);usage.setOnClickListener(v->startActivity(new Intent(Settings.ACTION_USAGE_ACCESS_SETTINGS)));admin.setOnClickListener(v->startActivity(new Intent(DevicePolicyManager.ACTION_ADD_DEVICE_ADMIN).putExtra(DevicePolicyManager.EXTRA_DEVICE_ADMIN,new ComponentName(this,AdminReceiver.class))));start.setOnClickListener(v->startChildService());stop.setOnClickListener(v->{stopService(new Intent(this,ChildServerService.class));out("Child background server stop requested");});root.addView(log);listenLogs();startChildService();}
    void startChildService(){getSharedPreferences("p",0).edit().putString("mode","child").putString("key",Base64.getEncoder().encodeToString(key)).putString("childId",childId).apply();Intent i=new Intent(this,ChildServerService.class);if(Build.VERSION.SDK_INT>=26)startForegroundService(i);else startService(i);out("Child background server start requested");}

    void startDiscoveryListener(){if(discoveryThread!=null&&discoveryThread.isAlive())return;discoveryRunning=true;discoveryThread=new Thread(()->{DatagramSocket ds=null;try{ds=new DatagramSocket(DISCOVERY_PORT);ds.setBroadcast(true);while(discoveryRunning){byte[] buf=new byte[512];DatagramPacket p=new DatagramPacket(buf,buf.length);ds.receive(p);String msg=new String(p.getData(),0,p.getLength(),StandardCharsets.UTF_8);String[] a=msg.split("\\|");if(a.length>=4&&"FAMILYLINK_CHILD".equals(a[0])&&childId.equals(a[1])){childIp=p.getAddress().getHostAddress();getSharedPreferences("p",0).edit().putString("childIp",childIp).apply();out("Found child broadcast at "+childIp);cmd("usage","today");}}}catch(Exception e){if(discoveryRunning)out("Discovery listener failed: "+e.getMessage());}finally{if(ds!=null)ds.close();}},"FamilyLinkParentDiscovery");discoveryThread.start();}
    void setConnected(boolean ok){runOnUiThread(()->{if(status==null)return;status.setText(ok?"Connected":"Disconnected");status.setBackgroundColor(ok?Color.rgb(210,245,210):Color.rgb(255,210,210));});}
    void cmd(String type,String value){new Thread(()->{try{if(childIp.length()==0||key==null){setConnected(false);out("No child connection saved");return;}JSONObject j=new JSONObject();j.put("type",type);j.put("value",value);Socket s=new Socket();s.connect(new InetSocketAddress(childIp,PORT),2500);PrintWriter w=new PrintWriter(s.getOutputStream(),true);w.println(encrypt(j.toString()));BufferedReader r=new BufferedReader(new InputStreamReader(s.getInputStream()));String line=r.readLine();s.close();String resp=decrypt(line);setConnected(true);if(resp.startsWith("USAGE_JSON:"))updateUsage(resp.substring(11));else out(resp);}catch(Exception e){setConnected(false);out("Command failed: "+e.getMessage());}}).start();}
    void updateUsage(String json){try{JSONObject o=new JSONObject(json);long total=o.optLong("totalMinutes",0);JSONArray apps=o.optJSONArray("apps");StringBuilder sb=new StringBuilder("Most active apps:\n");for(int i=0;i<3;i++){if(apps!=null&&i<apps.length()){JSONObject a=apps.getJSONObject(i);sb.append(i+1).append(". ").append(a.getString("name")).append(" — ").append(minToHHMM(a.getLong("minutes"))).append("\n");}else sb.append(i+1).append(". --\n");}runOnUiThread(()->{screenTime.setText("Today's screen time: "+minToHHMM(total));topApps.setText(sb.toString());});}catch(Exception e){out("Usage parse failed: "+e.getMessage());}}
    String minToHHMM(long m){return String.format(Locale.US,"%02d:%02d",m/60,m%60);} int checkCode(String s){return Math.abs(s.hashCode())%90000+10000;} String getOrCreateChildId(){String s=getSharedPreferences("p",0).getString("childId",null);if(s!=null)return s;String id=UUID.randomUUID().toString().substring(0,8);getSharedPreferences("p",0).edit().putString("childId",id).apply();return id;} byte[] getOrCreateKey(){String saved=getSharedPreferences("p",0).getString("key",null);if(saved!=null)return Base64.getDecoder().decode(saved);byte[] b=new byte[32];new SecureRandom().nextBytes(b);getSharedPreferences("p",0).edit().putString("key",Base64.getEncoder().encodeToString(b)).apply();return b;}
    String encrypt(String plain)throws Exception{byte[] iv=new byte[12];new SecureRandom().nextBytes(iv);Cipher c=Cipher.getInstance("AES/GCM/NoPadding");c.init(Cipher.ENCRYPT_MODE,new SecretKeySpec(key,"AES"),new GCMParameterSpec(128,iv));byte[] enc=c.doFinal(plain.getBytes(StandardCharsets.UTF_8));byte[] all=new byte[iv.length+enc.length];System.arraycopy(iv,0,all,0,iv.length);System.arraycopy(enc,0,all,iv.length,enc.length);return Base64.getEncoder().encodeToString(all);} String decrypt(String data)throws Exception{byte[] all=Base64.getDecoder().decode(data);byte[] iv=Arrays.copyOfRange(all,0,12);byte[] enc=Arrays.copyOfRange(all,12,all.length);Cipher c=Cipher.getInstance("AES/GCM/NoPadding");c.init(Cipher.DECRYPT_MODE,new SecretKeySpec(key,"AES"),new GCMParameterSpec(128,iv));return new String(c.doFinal(enc),StandardCharsets.UTF_8);} String getIp(){try{WifiManager wm=(WifiManager)getApplicationContext().getSystemService(WIFI_SERVICE);return Formatter.formatIpAddress(wm.getConnectionInfo().getIpAddress());}catch(Exception e){return "0.0.0.0";}}
    Bitmap qrBitmap(String text,int size){try{BitMatrix m=new MultiFormatWriter().encode(text,BarcodeFormat.QR_CODE,size,size);Bitmap bmp=Bitmap.createBitmap(size,size,Bitmap.Config.RGB_565);for(int x=0;x<size;x++)for(int y=0;y<size;y++)bmp.setPixel(x,y,m.get(x,y)?Color.BLACK:Color.WHITE);return bmp;}catch(Exception e){Bitmap b=Bitmap.createBitmap(10,10,Bitmap.Config.RGB_565);b.eraseColor(Color.LTGRAY);return b;}}
    void listenLogs(){try{if(br!=null)unregisterReceiver(br);}catch(Exception ignored){}br=new BroadcastReceiver(){public void onReceive(Context c,Intent i){out(i.getStringExtra("msg"));}};if(Build.VERSION.SDK_INT>=33)registerReceiver(br,new IntentFilter("com.enigma.familylinklite.LOG"),RECEIVER_NOT_EXPORTED);else registerReceiver(br,new IntentFilter("com.enigma.familylinklite.LOG"));} void out(String s){runOnUiThread(()->{if(log!=null)log.setText(s+"\n\n"+log.getText());});} void toast(String s){Toast.makeText(this,s,Toast.LENGTH_SHORT).show();}
}
